@click.command()
@click.option("--env", type=click.Choice(["dev", "staging", "prod"]), default="dev")
@click.option("--debug", is_flag=True)
@click.option(
    "--log-level",
    default={
        "--env": {"dev": "DEBUG", "staging": "INFO", "prod": "ERROR"},
        "--debug": {"True": "DEBUG"},
    },
)
def deploy(env, debug, log_level):
    click.echo(f"{env} {log_level} {debug}")

r = runner.invoke(deploy, ["--env", "prod"])
print("prod no debug:", r.output)
r = runner.invoke(deploy, ["--env", "prod", "--debug"])
print("prod debug:", r.output)

@click.command()
@click.option("--protocol", envvar="PROTOCOL", default="http")
@click.option("--port", default={"--protocol": {"http": 80, "https": 443}})
def server(protocol, port):
    click.echo(f"{protocol}:{port}")

r = runner.invoke(server, [], env={"PROTOCOL": "https"})
print("envvar:", r.output)

